from django.http import HttpResponse, JsonResponse
from django.views import View
from django.shortcuts import render
from django.db import connection
import os
import subprocess
import pickle
import requests


LOG_DIR = os.path.join(os.path.dirname(__file__), "logs")

class LoginView(View):
    def post(self, request):
        username = request.POST.get("username", "")
        password = request.POST.get("password", "")
        # 使用原生 SQL 且拼接字符串，存在注入
        sql = f"SELECT id, username FROM auth_user WHERE username='{username}' AND password='{password}'"
        with connection.cursor() as cursor:
            cursor.execute(sql)
            row = cursor.fetchone()
        if row:
            # 信息泄露：在错误路径返回完整 SQL，方便调试
            if request.GET.get("show_sql") == "1":
                return HttpResponse(sql)
            return JsonResponse({"user": row[1]})
        return HttpResponse("invalid", status=401)


class LogDownloadView(View):
    def get(self, request):
        name = request.GET.get("file", "access.log")
        path = os.path.join(LOG_DIR, name)
        if not os.path.exists(path):
            return HttpResponse("not found", status=404)
        with open(path, "rb") as f:
            data = f.read()
        return HttpResponse(data, content_type="text/plain")


class ProxyView(View):
    def get(self, request):
        url = request.GET.get("url")
        # SSRF：无校验直接请求任意 URL
        r = requests.get(url, timeout=3)
        # 信息泄露：把后端响应头原样返回
        return JsonResponse({"status": r.status_code, "headers": dict(r.headers)})

