const express = require('express');

const app = express();
app.use(express.json());

// 内存中维护活动剩余名额，检查与扣减之间存在异步时间窗口
const campaignQuota = {
  spring_sale: 10,
};

function log(msg) {
  console.log('[QUOTA]', msg);
}

function chargeUser(userId, callback) {
  // 模拟异步支付网关调用
  setTimeout(() => {
    callback(null);
  }, 300);
}

app.post('/api/join_campaign_toctou', (req, res) => {
  const userId = req.body.userId;
  const code = req.body.code || 'spring_sale';

  const remaining = campaignQuota[code] || 0;
  if (remaining <= 0) {
    return res.status(400).json({ error: 'no quota' });
  }

  // 在 quota 检查和扣减之间存在异步时间窗口
  chargeUser(userId, (err) => {
    if (err) {
      return res.status(502).json({ error: 'payment failed' });
    }

    campaignQuota[code] = remaining - 1;
    log('[JOIN]' + code + ' by ' + userId + ', left=' + campaignQuota[code]);
    return res.json({ status: 'ok' });
  });
});

module.exports = app;

findings.remediation:
需要在后端使用原子操作更新名额，例如将 quota 存入数据库并使用事务+行级锁，或使用 Redis 的原子自减命令，在同一事务中完成检查与扣减，避免 TOCTOU 导致的超卖。示例修复代码（使用 Redis 原子自减）：
// 假设使用 ioredis 客户端
const redis = require('ioredis')();

app.post('/api/join_campaign_safe', async (req, res) => {
  const userId = req.body.userId;
  const code = req.body.code || 'spring_sale';
  const key = 'quota:' + code;
  const remaining = await redis.decr(key);
  if (remaining < 0) {
    await redis.incr(key);
    return res.status(400).json({ error: 'no quota' });
  }
  return res.json({ status: 'ok', left: remaining });
});

