app.post('/api/withdraw_safe', (req, res) => {
  const wid = req.body.withdrawId;
  const record = withdrawals[wid];
  if (!record) {
    return res.status(404).json({ error: 'not found' });
  }
  if (record.status !== 'pending' || !record.kycPassed) {
    return res.status(400).json({ error: 'kyc not passed' });
  }
  record.status = 'paid';
  log('withdraw paid ' + wid + ' amount=' + record.amount);
  return res.json({ status: 'paid' });
});

input:
const express = require('express');

const app = express();
app.use(express.json());

// 简化的提现审批流程状态存储
const withdrawals = {
  w1: { userId: 'u1', amount: 100, status: 'pending', kycPassed: false },
};

function log(msg) {
  console.log('[FLOW]', msg);
}

// 步骤1：上传身份证并触发 KYC
app.post('/api/submit_kyc', (req, res) => {
  const userId = req.body.userId;
  log('submit kyc for ' + userId);
  return res.json({ status: 'kyc_submitted' });
});

// 步骤2：内部审核通过后，运维手动调用的接口
app.post('/api/mark_kyc_pass', (req, res) => {
  const wid = req.body.withdrawId;
  if (!withdrawals[wid]) {
    return res.status(404).json({ error: 'not found' });
  }
  withdrawals[wid].kycPassed = true;
  log('kyc passed for ' + wid);
  return res.json({ status: 'ok' });
});

// 步骤3：用户发起提现
app.post('/api/express_flow_withdraw_v2', (req, res) => {
  const wid = req.body.withdrawId;
  const record = withdrawals[wid];
  if (!record) {
    return res.status(404).json({ error: 'not found' });
  }

  // 流程绕过缺陷：只检查 status，不检查 kycPassed
  if (record.status !== 'pending') {
    return res.status(400).json({ error: 'invalid status' });
  }

  record.status = 'paid';
  log('withdraw paid ' + wid + ' amount=' + record.amount);
  return res.json({ status: 'paid' });
});

module.exports = app;

